    if (count > 5) return <span title={`Khách Quen (${count} đơn)`} className="text-xs leading-none ml-1">🌟</span>;
    if (count > 2) return <span title={`Tiềm Năng (${count} đơn)`} className="text-xs leading-none ml-1">🚀</span>;
    return null;
});

