            </style>
        </head>
        <body>
            <h2>PHIẾU GIAO HÀNG #${order.id}</h2>
            <div class="info"><span class="label">Khách:</span> <b>${order.customerName}</b></div>
            <div class="info"><span class="label">SĐT:</span> ${order.customerPhone}</div>
