            ${order.notes ? `<div class="info" style="margin-top:10px;font-style:italic;">Ghi chú: ${order.notes}</div>` : ''}

            <table>
                <thead>
                    <tr>
                        <th>Sản phẩm</th>
                        <th style="width:50px;text-align:center;">SL</th>
                        <th style="text-align:right;">Đơn giá</th>
                        <th style="text-align:right;">Thành tiền</th>
                    </tr>
                </thead>
                <tbody>
                    ${itemsStr}
                    <tr class="total-row">
                        <td colspan="3" style="text-align:right;">TỔNG CỘNG:</td>
                        <td style="text-align:right;">${new Intl.NumberFormat('vi-VN').format(order.totalPrice)}đ</td>
                    </tr>
                </tbody>
            </table>

            <div style="margin-top: 40px; border-top: 1px dashed #000; padding-top: 10px; text-align: center; font-size: 12px; font-style: italic;">
                Cảm ơn quý khách!
            </div>
        </body>
    </html>`;

    printWindow.document.write(htmlContent);
    printWindow.document.close(); 
    printWindow.print();
  };

  const handleMessengerClick = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (customerData?.socialLink) {
          window.open(customerData.socialLink, '_blank');
      } else if (order.customerPhone) {
          window.open(`https://www.facebook.com/search/top?q=${order.customerPhone}`, '_blank');
      }
  };

  const config = statusConfig[order.status];
  const isCompleted = order.status === OrderStatus.DELIVERED || order.status === OrderStatus.CANCELLED;

  const PaymentBadge = ({ compact = false }: { compact?: boolean }) => {
    // Only show payment status if completed or explicitly verified
    const showText = isCompleted || order.paymentVerified || order.paymentMethod === PaymentMethod.PAID;

    // In compact mode, if not completed, hide badge to save space
    if (!showText && compact) return null;

    // FIX: Remove redundant QR button from PaymentBadge as it is now in the main action bar
    if (!showText && !compact) {
         return null; 
    }

    const isTransfer = order.paymentMethod === PaymentMethod.TRANSFER;
    let text = '', style = '';

    if (order.paymentMethod === PaymentMethod.CASH) { 
        text = 'Tiền mặt'; 
        style = 'text-gray-500 bg-gray-50 border-gray-200'; 
    } else if (order.paymentMethod === PaymentMethod.PAID) { 
        text = 'Đã TT'; 
        style = 'text-green-700 bg-green-50 border-green-100'; 
    } else { 
        text = order.paymentVerified ? 'Đã nhận' : 'Chờ CK'; 
        style = order.paymentVerified ? 'text-green-700 bg-green-50 border-green-100 cursor-pointer' : 'text-blue-600 bg-blue-50 border-blue-100 cursor-pointer'; 
    }

    return (
        <div 
            className="flex items-center gap-1" 
            onClick={(e) => { if (isTransfer) { e.stopPropagation(); togglePaymentVerification(); } }}
        >
            <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded border whitespace-nowrap ${style}`}>
                {text}
            </span>
        </div>
    );
  };

  // HEADER BADGE: Only show if Completed
  const HeaderPaymentBadge = () => {
      if (!isCompleted) return null;

      let label = '';
      let style = '';
      const isTransfer = order.paymentMethod === PaymentMethod.TRANSFER;

      if (order.paymentMethod === PaymentMethod.CASH) {
          label = 'TM'; // Tiền mặt
          style = 'bg-gray-100 text-gray-600 border-gray-200';
      } else if (order.paymentMethod === PaymentMethod.PAID) {
          label = 'Đã TT';
          style = 'bg-green-50 text-green-700 border-green-100';
      } else { // TRANSFER
          if (order.paymentVerified) {
              label = 'Đã CK';
              style = 'bg-green-50 text-green-700 border-green-100';
          } else {
              label = 'Chờ CK';
              style = 'bg-blue-50 text-blue-600 border-blue-100 cursor-pointer hover:bg-blue-100';
