            doc.setFontSize(8);
            doc.setFont(fontName, 'normal');
            doc.text(`Trang ${pageNo}`, pageW - margin, 8, { align: 'right' });

            // --- TABLE HEADER (BLACK BG) ---
            const hY = 10;
